function transform (message, context) {
  const contextUser = context.get('__user');
  const testPersonId = context.get('testPersonId');

  const personId = contextUser?.id || testPersonId;

  context.set('personId', personId);

  return { payload: { personId } };
}

function transform (message, context) {
  const { payload, payload: { credentials } = {} } = message;

  const bannerCredential = (credentials || []).find(c => c.type === 'bannerId');
  const bannerId = bannerCredential && bannerCredential.value;

  if (!bannerId) {
    const msg = 'Unable to resolve Banner ID for the current user';
    context.set('__httpStatusCode', 404);
    context.set('__httpStatusMessage', {
      correlationId: context['__runId'],
      component: context['__pipelineName'] + ':Resolve bannerId',
      error: '404',
      message: msg
    });
    throw new Error(msg);
  }

  context.set('bannerId', bannerId);

  return { ...message, payload: { ...payload, bannerId } };
}

function transform (message, context) {
  // award_maintenance (RPRAWRD) rows for this student + aid year
  const awards = Array.isArray(message.payload) ? message.payload : [];
  context.set('awards', awards);
  return { payload: {} };
}

function transform (message, context) {
  // applicant_requirements (RRAAREQ) rows for this student + aid year + treqCode
  const requirements = Array.isArray(message.payload) ? message.payload : [];

  const awards = context.get('awards') || [];
  const aidYear = context.get('aidYear');
  const bannerId = context.get('bannerId');
  const treqCode = context.get('attestationTreqCode');
  const trstYes = context.get('trstCodeYes');
  const trstNo = context.get('trstCodeNo');

  const fundCodes = String(context.get('texasGrantFundCodes') || '')
    .split(',')
    .map(s => s.trim().toUpperCase())
    .filter(Boolean);

  const eligible = awards.some(a => a && fundCodes.includes(String(a.fundCode || '').toUpperCase()));

  // Find an existing attestation row for the configured requirement code
  const existing = requirements.find(r => r && String(r.treqCode) === String(treqCode));

  let currentAnswer = null;
  let statDate = null;
  if (existing) {
    statDate = existing.statDate || null;
    if (String(existing.trstCode) === String(trstYes)) {
      currentAnswer = true;
    } else if (String(existing.trstCode) === String(trstNo)) {
      currentAnswer = false;
    }
  }

  return {
    payload: {
      eligible,
      bannerId,
      aidYear,
      currentAnswer,
      currentStatus: existing ? existing.trstCode : null,
      statDate
    }
  };
}
